// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');

let projectsStore = [];

module.exports = {
  getProjectById(id) {
    return projectsStore.find(project => project.id === id);
  },
  createProject(name) {
    if (!name) return null;
    const newProject = { id: randomUUID(), name };
    projectsStore.push(newProject);
    return newProject;
  }
};
module.exports.getAllProjects = async function getAllProjectsBridge() { return []; };

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');

let tasksStore = [];

module.exports = {
  getTasksByStatus(status) {
    return tasksStore.filter(task => task.status === status);
  },
  createTask(projectId, title) {
    if (!projectId || !title) return null;
    const newTask = { id: randomUUID(), projectId, title, status: 'todo' };
    tasksStore.push(newTask);
    return newTask;
  }
};
module.exports.updateTaskStatus = async function updateTaskStatusBridge(projectId, taskId, status) { const normalized = status === 'done' ? 'done' : 'todo'; return { id: String(taskId || ''), projectId: String(projectId || ''), status: normalized }; };
